 12→use crate::zq::{Zq, mul_mod, sub_mod};
 13→
 14→/// Zq value in the low half: [0, (Q-1)/2] = [0, 6144]
 15→type ZqLow = BoundedInt<0, 6144>;
 16→const Q_felt252: felt252 = 12289;
 17→
 18→/// Compute the squared centered norm of a single Zq element.
 19→fn center_and_square(coeff: Zq) -> felt252 {
 20→    match downcast::<Zq, ZqLow>(coeff) {
 21→        Option::Some(low) => {
 22→            let x: felt252 = upcast(low);
 23→            x * x
 24→        },
 25→        Option::None => {
 26→            let x: felt252 = upcast(coeff);
 27→            let centered = Q_felt252 - x;
 28→            centered * centered
 29→        },
 30→    }
 31→}
 32→
 33→/// Signature bound for Falcon-512
 34→const SIG_BOUND_512: u64 = 34034726;
 35→
 36→/// Verify a Falcon signature using the hint-based approach.
 37→/// Computes msg_point internally via hash_to_point.
 38→/// Cost: 2 NTTs, 0 INTTs.
 39→pub fn verify<H, +HashToPoint<H>, +Drop<H>>(
 40→    pk: @FalconPublicKey, sig_with_hint: FalconSignatureWithHint, message: Span<felt252>,
 41→) -> bool {
 42→    let msg_point = HashToPoint::<H>::hash_to_point(message, sig_with_hint.signature.salt.span());
 43→    verify_with_msg_point(pk, sig_with_hint, msg_point.span())
 44→}
 45→
 46→/// Verify with a pre-computed msg_point (useful for testing without hash_to_point).
 47→///
 48→/// Single-pass verification: 2 unrolled NTTs + 1 fused loop that does
 49→/// hint verification, pointwise multiply check, and norm computation.
 50→pub fn verify_with_msg_point(
 51→    pk: @FalconPublicKey, sig_with_hint: FalconSignatureWithHint, msg_point: Span<Zq>,
 52→) -> bool {
 53→    let s1 = sig_with_hint.signature.s1.span();
 54→    let pk_ntt = pk.h_ntt.span();
 55→    let mul_hint = sig_with_hint.hint.mul_hint.span();
 56→
 57→    assert!(s1.len() == 512, "s1 must be 512 elements");
 58→    assert!(pk_ntt.len() == 512, "pk must be 512 elements");
 59→    assert!(mul_hint.len() == 512, "mul_hint must be 512 elements");
 60→    assert!(msg_point.len() == 512, "msg_point must be 512 elements");
 61→
 62→    // Two forward NTTs (unrolled, no loops)
 63→    let s1_ntt = ntt_fast(s1);
 64→    let hint_ntt = ntt_fast(mul_hint);
 65→
 66→    // Single pass over all 512 coefficients:
 67→    //   - Verify hint: s1_ntt[i] * pk_ntt[i] == NTT(mul_hint)[i]
 68→    //   - Accumulate: ||msg_point - mul_hint||² + ||s1||²
 69→    let mut s1_ntt_iter = s1_ntt.span();
 70→    let mut pk_ntt_iter = pk_ntt;
 71→    let mut hint_ntt_iter = hint_ntt.span();
 72→    let mut msg_iter = msg_point;
 73→    let mut hint_iter = mul_hint;
 74→    let mut s1_iter = s1;
 75→
 76→    let mut acc: felt252 = 0;
 77→    while let Some(s1n_box) = s1_ntt_iter.multi_pop_front::<8>() {
 78→        let [s1n0, s1n1, s1n2, s1n3, s1n4, s1n5, s1n6, s1n7] = s1n_box.unbox();
 79→        let [pkn0, pkn1, pkn2, pkn3, pkn4, pkn5, pkn6, pkn7] = pk_ntt_iter
 80→            .multi_pop_front::<8>()
 81→            .unwrap()
 82→            .unbox();
 83→        let [hn0, hn1, hn2, hn3, hn4, hn5, hn6, hn7] = hint_ntt_iter
 84→            .multi_pop_front::<8>()
 85→            .unwrap()
 86→            .unbox();
 87→        let [msg0, msg1, msg2, msg3, msg4, msg5, msg6, msg7] = msg_iter
 88→            .multi_pop_front::<8>()
 89→            .unwrap()
 90→            .unbox();
 91→        let [hint0, hint1, hint2, hint3, hint4, hint5, hint6, hint7] = hint_iter
 92→            .multi_pop_front::<8>()
 93→            .unwrap()
 94→            .unbox();
 95→        let [s1v0, s1v1, s1v2, s1v3, s1v4, s1v5, s1v6, s1v7] = s1_iter
 96→            .multi_pop_front::<8>()
 97→            .unwrap()
 98→            .unbox();
 99→
100→        // Verify: NTT(s1)[i] * pk_ntt[i] == NTT(mul_hint)[i]
101→        assert(mul_mod(s1n0, pkn0) == hn0, 'hint mismatch');
102→        assert(mul_mod(s1n1, pkn1) == hn1, 'hint mismatch');
103→        assert(mul_mod(s1n2, pkn2) == hn2, 'hint mismatch');
104→        assert(mul_mod(s1n3, pkn3) == hn3, 'hint mismatch');
105→        assert(mul_mod(s1n4, pkn4) == hn4, 'hint mismatch');
106→        assert(mul_mod(s1n5, pkn5) == hn5, 'hint mismatch');
107→        assert(mul_mod(s1n6, pkn6) == hn6, 'hint mismatch');
108→        assert(mul_mod(s1n7, pkn7) == hn7, 'hint mismatch');
109→
110→        // Accumulate: ||msg_point - mul_hint||² + ||s1||²
111→        acc += center_and_square(sub_mod(msg0, hint0))
112→            + center_and_square(s1v0)
113→            + center_and_square(sub_mod(msg1, hint1))
114→            + center_and_square(s1v1)
115→            + center_and_square(sub_mod(msg2, hint2))
116→            + center_and_square(s1v2)
117→            + center_and_square(sub_mod(msg3, hint3))
118→            + center_and_square(s1v3)
119→            + center_and_square(sub_mod(msg4, hint4))
120→            + center_and_square(s1v4)
121→            + center_and_square(sub_mod(msg5, hint5))
122→            + center_and_square(s1v5)
123→            + center_and_square(sub_mod(msg6, hint6))
124→            + center_and_square(s1v6)
125→            + center_and_square(sub_mod(msg7, hint7))
126→            + center_and_square(s1v7);
127→    }
128→
129→    let norm_u64: u64 = acc.try_into().unwrap();
130→    norm_u64 <= SIG_BOUND_512
131→}
