133→/// Verify a Falcon signature from packed (29 felt252) inputs.
134→/// Unpacks PK, s1, and mul_hint, then delegates to verify.
135→pub fn verify_packed<H, +HashToPoint<H>, +Drop<H>>(
136→    pk: @PackedPolynomial512, sig: PackedFalconSignatureWithHint, message: Span<felt252>,
137→) -> bool {
138→    let pk_coeffs = pk.to_coeffs();
139→    let s1_coeffs = sig.signature.s1.to_coeffs();
140→    let mul_hint_coeffs = sig.hint.mul_hint.to_coeffs();
141→    let falcon_pk = FalconPublicKey { h_ntt: pk_coeffs };
142→    let sig_with_hint = FalconSignatureWithHint {
143→        signature: FalconSignature { s1: s1_coeffs, salt: sig.signature.salt },
144→        hint: FalconVerificationHint { mul_hint: mul_hint_coeffs },
145→    };
146→    verify::<H>(@falcon_pk, sig_with_hint, message)
147→}
