17→// Starting type: u128 = BoundedInt<0, 2^128-1>
18→// Each DivRem by Q removes ~13.585 bits. 6 safe coefficients (input >= 50 bits).
19→// =============================================================================
20→
21→type ExtractLQ1 = BoundedInt<0, 27689996494502275487295516920153650>;
22→type ExtractLQ2 = BoundedInt<0, 2253234314793903123711898195146>;
23→type ExtractLQ3 = BoundedInt<0, 183353756594833031468133956>;
24→type ExtractLQ4 = BoundedInt<0, 14920152705251284194656>;
25→type ExtractLQ5 = BoundedInt<0, 1214106331292317047>;
