119→    pub impl InternalImpl<
120→        TContractState,
121→        +HasComponent<TContractState>,
122→        impl SRC5: SRC5Component::HasComponent<TContractState>,
123→        +Drop<TContractState>,
124→    > of InternalTrait<TContractState> {
125→        /// Initializes the account with a packed Falcon public key.
126→        /// Registers the ISRC6 interface.
127→        fn initializer(ref self: ComponentState<TContractState>, pk: PackedPolynomial512) {
128→            let mut src5_component = get_dep_component_mut!(ref self, SRC5);
129→            src5_component.register_interface(interface::ISRC6_ID);
130→            self.write_packed_pk(pk);
131→        }
132→
133→        /// Validates the signature for the current transaction.
134→        /// Returns the short string 'VALID' if valid, otherwise reverts.
135→        fn validate_transaction(self: @ComponentState<TContractState>) -> felt252 {
136→            let tx_info = starknet::get_tx_info().unbox();
137→            let tx_hash = tx_info.transaction_hash;
138→            let signature = tx_info.signature;
139→            assert(self._is_valid_signature(tx_hash, signature), Errors::INVALID_SIGNATURE);
140→            starknet::VALIDATED
141→        }
142→
143→        /// Returns whether the given signature is valid for the given hash.
144→        fn _is_valid_signature(
145→            self: @ComponentState<TContractState>, hash: felt252, signature: Span<felt252>,
146→        ) -> bool {
147→            let mut sig_span = signature;
148→            let sig: PackedFalconSignatureWithHint = match Serde::deserialize(ref sig_span) {
149→                Option::Some(s) => s,
150→                Option::None => { return false; },
151→            };
152→            let pk = self.read_packed_pk();
153→            let message = array![hash];
154→            verify_packed::<PoseidonHashToPoint>(@pk, sig, message.span())
155→        }
156→
157→        /// Returns the packed public key.
158→        fn get_public_key(self: @ComponentState<TContractState>) -> PackedPolynomial512 {
159→            self.read_packed_pk()
160→        }
161→
162→        /// Reads the 29 packed PK slots from storage into a PackedPolynomial512.
163→        fn read_packed_pk(self: @ComponentState<TContractState>) -> PackedPolynomial512 {
164→            PackedPolynomial512 {
165→                s0: self.pk_0.read(),
166→                s1: self.pk_1.read(),
167→                s2: self.pk_2.read(),
168→                s3: self.pk_3.read(),
169→                s4: self.pk_4.read(),
170→                s5: self.pk_5.read(),
