 1→/// Minimum transaction version for invoke transactions.
 2→pub const MIN_TRANSACTION_VERSION: u256 = 1;
 3→
 4→/// Query offset for simulation transactions.
 5→pub const QUERY_OFFSET: u256 = 0x100000000000000000000000000000000;
 6→
 7→/// Validates that the current transaction version is supported.
 8→/// Regular transactions must be >= MIN_TRANSACTION_VERSION.
 9→/// Simulation transactions (version >= QUERY_OFFSET) must be >= QUERY_OFFSET +
10→/// MIN_TRANSACTION_VERSION.
11→pub fn is_tx_version_valid() -> bool {
12→    let tx_info = starknet::get_tx_info().unbox();
13→    let tx_version: u256 = tx_info.version.into();
14→    if tx_version >= QUERY_OFFSET {
15→        QUERY_OFFSET + MIN_TRANSACTION_VERSION <= tx_version
16→    } else {
17→        MIN_TRANSACTION_VERSION <= tx_version
18→    }
19→}
