  1→# Effect + Next.js Integration
  2→
  3→`@prb/effect-next` provides typed helpers for integrating Effect with Next.js 15+ App Router—route handlers, server
  4→actions, middleware, and React hooks.
  5→
  6→## Core API
  7→
  8→### Route Handlers
  9→
 10→```typescript
 11→// app/api/users/[id]/route.ts
 12→import { effectHandler } from "@prb/effect-next/handlers";
 13→import { Effect } from "effect";
 14→import { RouteParams } from "@prb/effect-next/params";
 15→
 16→export const GET = effectHandler(
 17→  Effect.gen(function* () {
 18→    const params = yield* RouteParams;
 19→    const user = yield* fetchUser(params.id);
 20→    return Response.json(user);
 21→  }),
 22→  AppLayer
 23→);
 24→```
 25→
 26→### Server Actions
 27→
 28→```typescript
 29→"use server";
 30→import { effectAction } from "@prb/effect-next/action";
 31→import { Effect } from "effect";
 32→
 33→export const createUser = effectAction(
 34→  Effect.gen(function* () {
 35→    const db = yield* Database;
 36→    return yield* db.insert(users).values({ name: "Alice" });
 37→  }),
 38→  AppLayer
 39→);
 40→
 41→// Returns Exit-like result with _tag: "Success" | "Failure"
 42→const result = await createUser();
 43→if (result._tag === "Success") {
 44→  console.log(result.value);
 45→}
 46→```
 47→
 48→### Middleware
 49→
 50→```typescript
 51→// middleware.ts
 52→import { effectMiddleware } from "@prb/effect-next/middleware";
 53→import { Effect, Layer } from "effect";
 54→import { Headers } from "@prb/effect-next/headers";
 55→
 56→const AuthLayer = Layer.effect(
 57→  AuthService,
 58→  Effect.gen(function* () {
 59→    const headers = yield* Headers;
 60→    const token = headers.get("authorization");
 61→    if (!token) yield* Effect.fail({ _tag: "Unauthorized" });
 62→    return { validateToken: () => Effect.succeed(true) };
 63→  })
 64→);
 65→
 66→export const middleware = effectMiddleware(
 67→  Effect.gen(function* () {
 68→    yield* AuthService;
 69→    return NextResponse.next();
 70→  }),
 71→  AuthLayer
 72→);
 73→```
 74→
 75→## React Hooks
 76→
 77→Client-side hooks for running Effects in React components.
 78→
 79→```typescript
 80→"use client";
 81→import {
 82→  EffectNextProvider,
 83→  useEffectNextRuntime,
 84→  useEffectMemo,
 85→  useEffectOnce,
 86→  useForkEffect,
 87→  useStream,
 88→  useStreamLatest,
 89→  useSubscriptionRef
 90→} from "@prb/effect-next/react-hooks";
 91→
 92→// Wrap app with provider
 93→<EffectNextProvider runtime={runtime}>{children}</EffectNextProvider>;
 94→
 95→// Access runtime
 96→const runtime = useEffectNextRuntime();
 97→
 98→// Run Effect with dependencies (like useMemo)
 99→const data = useEffectMemo(() => effect, [deps], runtime);
100→
101→// Run Effect once on mount
102→const data = useEffectOnce(effect, runtime);
103→
104→// Run Effect in background (fire-and-forget)
105→useForkEffect(effect, runtime, [deps]);
106→
107→// Subscribe to Stream
108→const values = useStream(stream, runtime);
109→const latest = useStreamLatest(stream, runtime, initialValue);
110→
111→// Subscribe to SubscriptionRef
112→const value = useSubscriptionRef(ref, runtime);
113→```
114→
115→## Request-Scoped Cache
116→
117→Leverage React's `cache()` for request deduplication.
118→
119→```typescript
120→import { reactCache, reactCacheFn, reactCacheWithKey } from "@prb/effect-next/cache";
121→import { ManagedRuntime } from "effect";
122→
123→const runtime = ManagedRuntime.make(AppLayer);
124→
125→// Cache an Effect
126→export const getUsers = reactCache(
127→  Effect.gen(function* () {
128→    const db = yield* Database;
129→    return yield* db.query("SELECT * FROM users");
130→  }),
131→  runtime
132→);
133→
134→// Cache a function with arguments
135→export const getUserById = reactCacheFn((id: string) =>
136→  Effect.gen(function* () {
137→    const db = yield* Database;
138→    return yield* db.query(`SELECT * FROM users WHERE id = ${id}`);
139→  }),
140→  runtime
141→);
142→
143→// Cache with custom key
144→export const getUser = reactCacheWithKey(
145→  (opts) => fetchUserEffect(opts),
146→  (opts) => `user:${opts.id}`,
147→  runtime
148→);
149→```
150→
151→## Headers & Cookies
152→
153→```typescript
154→import { Headers, Cookies } from "@prb/effect-next/headers";
155→
156→Effect.gen(function* () {
157→  const headers = yield* Headers;
158→  const userAgent = headers.get("user-agent");
159→
160→  const cookies = yield* Cookies;
161→  const sessionId = cookies.get("sessionId");
162→});
163→```
164→
165→## Params
166→
167→```typescript
168→import { RouteParams, SearchParams } from "@prb/effect-next/params";
169→
170→Effect.gen(function* () {
171→  const params = yield* RouteParams;
172→  const userId = params.id;
173→
174→  const searchParams = yield* SearchParams;
175→  const page = searchParams.page;
176→});
177→```
178→
179→## Navigation
180→
181→```typescript
182→import { redirect, rewrite, notFound } from "@prb/effect-next/navigation";
183→
184→Effect.gen(function* () {
185→  yield* redirect("/login");
186→  yield* rewrite("/new-path");
187→  yield* notFound();
188→});
189→```
190→
191→## Testing Kit
192→
193→```typescript
194→import {
195→  assertRight,
196→  assertLeft,
197→  expectTaggedFailure,
198→  expectDefect,
199→  runExpectSuccess,
200→  runExpectFailure,
201→  makeMockRuntime
202→} from "@prb/effect-next/testing-kit";
203→
204→// Assert success
205→test("should succeed", async () => {
206→  const exit = await Effect.runPromiseExit(effect);
207→  const value = assertRight(exit);
208→  expect(value).toBe(42);
209→});
210→
211→// Assert specific failure tag
212→test("should fail with NotFound", async () => {
213→  const exit = await Effect.runPromiseExit(effect);
214→  expectTaggedFailure(exit, "NotFound");
215→});
216→
217→// Run and expect success
218→test("should create user", async () => {
219→  const user = await runExpectSuccess(createUser(), runtime);
220→  expect(user.name).toBe("Alice");
221→});
222→```
223→
224→## Best Practices
225→
226→1. **Use `Effect.fn()`** — Automatic telemetry spans and better stack traces
227→2. **Centralize layers** — Create `AppLayer` with all shared services
228→3. **Error handling** — Use `.catchAll()` or `.catchTag()` for Effect-level errors
229→4. **Request caching** — Use `reactCache` for request-scoped memoization
230→5. **Server-only Effect** — Effect-ts shines server-side; avoid complex Effect in client components
