 54→/// Secret key for Falcon-512.
 55→///
 56→/// Contains the NTRU secret polynomials (f, g, F, G) and precomputed
 57→/// values for efficient signing. The secret key is used to produce
 58→/// signatures via lattice-based Gaussian sampling.
 59→///
 60→/// # Security
 61→///
 62→/// The secret key must be kept confidential. Exposure allows an attacker
 63→/// to forge signatures.
 64→pub struct SecretKey {
 65→    /// NTRU secret polynomial f.
 66→    f: [i32; N],
 67→    /// NTRU secret polynomial g.
 68→    g: [i32; N],
 69→    /// NTRU secret polynomial F.
 70→    capital_f: [i32; N],
 71→    /// NTRU secret polynomial G.
 72→    capital_g: [i32; N],
 73→    /// Basis B0 in FFT representation.
 74→    b0_fft: [[Vec<Complex>; 2]; 2],
 75→    /// LDL tree for fast sampling.
 76→    tree: LdlTree,
 77→}
 78→
 79→/// Verifying key (public key) for Falcon-512.
 80→///
 81→/// Contains the public polynomial h = g/f mod (X^n + 1, q).
 82→/// Used to verify signatures without access to the secret key.
 83→///
 84→/// # Serialization
 85→///
 86→/// The verifying key serializes to 896 bytes (512 coefficients at 14 bits each).
 87→#[derive(Clone)]
 88→pub struct VerifyingKey {
 89→    /// Public key h = g/f mod (x^n + 1, q).
 90→    h: [i32; N],
 91→}
 92→
 93→/// Signature for Falcon-512.
 94→///
 95→/// A Falcon signature consists of:
 96→/// - A header byte encoding the parameter set (log2(n))
 97→/// - A random salt (40 bytes)
 98→/// - A compressed polynomial s1
 99→///
100→/// # Serialization
101→///
102→/// The signature serializes to 666 bytes for Falcon-512.
103→pub struct Signature {
104→    /// Header byte (encodes log(n)).
105→    header: u8,
106→    /// Random salt.
107→    salt: [u8; SALT_LEN],
108→    /// Compressed signature polynomial s1.
109→    s1_enc: Vec<u8>,
110→}
111→
112→impl SecretKey {
113→    /// Serialize the secret key to bytes.
114→    ///
115→    /// Format: f || g || F || G (4 polynomials, each 896 bytes).
116→    pub fn to_bytes(&self) -> Vec<u8> {
117→        let mut bytes = Vec::with_capacity(4 * PUBLIC_KEY_LEN);
118→        bytes.extend_from_slice(&serialize_public_key(&self.f));
119→        bytes.extend_from_slice(&serialize_public_key(&self.g));
120→        bytes.extend_from_slice(&serialize_public_key(&self.capital_f));
121→        bytes.extend_from_slice(&serialize_public_key(&self.capital_g));
122→        bytes
123→    }
124→}
125→
126→impl VerifyingKey {
127→    /// Create a verifying key from raw h polynomial.
128→    pub fn from_h(h: [i32; N]) -> Self {
129→        VerifyingKey { h }
130→    }
131→
132→    /// Get a reference to the raw public key polynomial h.
133→    pub fn h(&self) -> &[i32; N] {
134→        &self.h
135→    }
136→
137→    /// Serialize the verifying key to bytes.
138→    pub fn to_bytes(&self) -> [u8; PUBLIC_KEY_LEN] {
139→        let vec = serialize_public_key(&self.h);
140→        let mut arr = [0u8; PUBLIC_KEY_LEN];
141→        arr.copy_from_slice(&vec);
142→        arr
143→    }
144→
145→    /// Deserialize a verifying key from bytes.
146→    pub fn from_bytes(bytes: &[u8; PUBLIC_KEY_LEN]) -> Result<Self, FalconError> {
147→        let h = deserialize_public_key(bytes).ok_or(FalconError::InvalidPublicKey)?;
148→        Ok(VerifyingKey { h })
149→    }
150→}
151→
152→impl Signature {
153→    /// Create a signature from raw components.
154→    pub fn from_components(header: u8, salt: [u8; SALT_LEN], s1_enc: Vec<u8>) -> Self {
155→        Signature {
156→            header,
157→            salt,
158→            s1_enc,
159→        }
160→    }
161→
162→    /// Serialize the signature to bytes.
163→    pub fn to_bytes(&self) -> Vec<u8> {
164→        let mut bytes = Vec::with_capacity(HEAD_LEN + SALT_LEN + self.s1_enc.len());
165→        bytes.push(self.header);
166→        bytes.extend_from_slice(&self.salt);
167→        bytes.extend_from_slice(&self.s1_enc);
168→        bytes
169→    }
170→
171→    /// Deserialize a signature from bytes.
172→    pub fn from_bytes(bytes: &[u8]) -> Result<Self, FalconError> {
173→        if bytes.len() < HEAD_LEN + SALT_LEN {
174→            return Err(FalconError::InvalidSignature);
175→        }
176→
177→        let header = bytes[0];
178→        if header != 0x30 + LOGN {
179→            return Err(FalconError::InvalidSignature);
180→        }
181→
182→        let mut salt = [0u8; SALT_LEN];
183→        salt.copy_from_slice(&bytes[HEAD_LEN..HEAD_LEN + SALT_LEN]);
184→
185→        let s1_enc = bytes[HEAD_LEN + SALT_LEN..].to_vec();
186→
187→        Ok(Signature {
188→            header,
189→            salt,
190→            s1_enc,
191→        })
192→    }
193→}
194→
195→/// Falcon-512 signature scheme parameterized by hash function.
196→///
197→/// The `Falcon` struct provides the core cryptographic operations:
198→/// key generation, signing, and verification.
199→///
200→/// # Type Parameter
201→///
202→/// - `H`: The hash function used to map messages to polynomials.
203→///   Use [`Shake256Hash`](crate::hash_to_point::Shake256Hash) for standard
204→///   Falcon or [`PoseidonHashToPoint`](crate::poseidon_hash::PoseidonHashToPoint) for
205→///   Starknet compatibility.
206→///
207→/// # Example
208→///
209→/// ```rust,ignore
210→/// use falcon_rs::falcon::Falcon;
211→/// use falcon_rs::hash_to_point::Shake256Hash;
212→///
213→/// let (sk, vk) = Falcon::<Shake256Hash>::keygen();
214→/// let sig = Falcon::<Shake256Hash>::sign(&sk, b"message");
215→/// assert!(Falcon::<Shake256Hash>::verify(&vk, b"message", &sig).unwrap());
216→/// ```
217→pub struct Falcon<H: HashToPoint> {
218→    _marker: PhantomData<H>,
219→}
220→
221→impl<H: HashToPoint> Falcon<H> {
222→    /// Generate a new keypair using system randomness.
223→    ///
224→    /// Creates a fresh Falcon-512 keypair using the system's cryptographically
225→    /// secure random number generator.
226→    ///
227→    /// # Returns
228→    ///
229→    /// A tuple of (secret key, verifying key).
230→    ///
231→    /// # Panics
232→    ///
233→    /// Panics if the system RNG fails to provide random bytes.
234→    #[cfg(feature = "shake")]
235→    pub fn keygen() -> (SecretKey, VerifyingKey) {
236→        use getrandom::getrandom;
237→        let mut seed = [0u8; 32];
238→        getrandom(&mut seed).expect("Failed to get random bytes");
239→        Self::keygen_with_seed(&seed)
240→    }
241→
242→    /// Generate a new keypair with a provided seed.
243→    ///
244→    /// Creates a deterministic Falcon-512 keypair from the given seed.
245→    /// The same seed will always produce the same keypair, which is
246→    /// useful for testing and key recovery.
247→    ///
248→    /// # Arguments
249→    ///
250→    /// * `seed` - A seed slice (up to 56 bytes used; shorter seeds are zero-padded)
251→    ///
252→    /// # Returns
253→    ///
254→    /// A tuple of (secret key, verifying key).
255→    pub fn keygen_with_seed(seed: &[u8]) -> (SecretKey, VerifyingKey) {
256→        // Create a deterministic RNG from the seed
257→        let mut full_seed = [0u8; SEED_LEN];
258→        let copy_len = seed.len().min(SEED_LEN);
259→        full_seed[..copy_len].copy_from_slice(&seed[..copy_len]);
260→        let mut rng = ChaCha20::new(&full_seed);
261→        let mut random_bytes = |n: usize| rng.random_bytes(n);
262→
263→        Self::keygen_with_rng(&mut random_bytes)
264→    }
265→
266→    /// Generate a new keypair with a provided random byte source.
267→    ///
268→    /// Creates a Falcon-512 keypair using a custom source of randomness.
269→    /// This is the most flexible key generation method, useful for
270→    /// deterministic testing or custom RNG implementations.
271→    ///
272→    /// # Arguments
273→    ///
274→    /// * `random_bytes` - A closure that returns `n` random bytes when called
275→    ///
276→    /// # Returns
277→    ///
278→    /// A tuple of (secret key, verifying key).
279→    pub fn keygen_with_rng<F: FnMut(usize) -> Vec<u8>>(
280→        random_bytes: &mut F,
281→    ) -> (SecretKey, VerifyingKey) {
282→        // Generate NTRU polynomials
283→        let (f, g, capital_f, capital_g) = ntru_gen(random_bytes);
284→
285→        // Compute public key h = g/f mod (x^n + 1, q)
286→        let f_vec: Vec<i32> = f.iter().copied().collect();
287→        let g_vec: Vec<i32> = g.iter().copied().collect();
288→        let h_vec = div_zq(&g_vec, &f_vec).expect("f should be invertible");
289→        let mut h = [0i32; N];
290→        h.copy_from_slice(&h_vec);
291→
292→        // Compute basis B0 = [[g, -f], [G, -F]] in coefficient representation
293→        // Note: Use regular negation, NOT modular negation (neg_zq), for the Gram matrix
294→        let neg_f: Vec<f64> = f_vec.iter().map(|&x| -(x as f64)).collect();
295→        let neg_f_cap: Vec<f64> = capital_f.iter().map(|&x| -(x as f64)).collect();
296→
297→        // B0 in coefficient representation (f64 for Gram computation)
298→        let b0: [[Vec<f64>; 2]; 2] = [
299→            [g_vec.iter().map(|&x| x as f64).collect(), neg_f],
300→            [capital_g.iter().map(|&x| x as f64).collect(), neg_f_cap],
301→        ];
302→
303→        // Convert B0 to FFT representation (for use in signing)
304→        let b0_fft = [
305→            [fft(&b0[0][0]), fft(&b0[0][1])],
306→            [fft(&b0[1][0]), fft(&b0[1][1])],
307→        ];
308→
309→        // Compute Gram matrix G0 = B0 * B0^* in coefficient representation
310→        // (matching Python's approach: gram() in coef domain, then FFT)
311→        let g0 = gram(&b0);
312→        let g0_fft = [
313→            [fft(&g0[0][0]), fft(&g0[0][1])],
314→            [fft(&g0[1][0]), fft(&g0[1][1])],
315→        ];
316→
317→        // Build ffLDL tree
318→        let mut tree = ffldl_fft(&g0_fft);
319→        normalize_tree(&mut tree, SIGMA);
320→
321→        let sk = SecretKey {
322→            f,
323→            g,
324→            capital_f,
325→            capital_g,
326→            b0_fft,
327→            tree,
328→        };
329→
330→        let vk = VerifyingKey { h };
331→
332→        (sk, vk)
333→    }
334→
335→    /// Sign a message.
336→    ///
337→    /// Creates a Falcon-512 signature over the given message using
338→    /// the secret key. A fresh random salt is generated for each signature.
339→    ///
340→    /// # Arguments
341→    ///
342→    /// * `sk` - The secret key to sign with
343→    /// * `message` - The message bytes to sign
344→    ///
345→    /// # Returns
346→    ///
347→    /// A signature that can be verified with the corresponding verifying key.
348→    ///
349→    /// # Panics
350→    ///
351→    /// Panics if the system RNG fails to provide random bytes.
352→    #[cfg(feature = "shake")]
353→    pub fn sign(sk: &SecretKey, message: &[u8]) -> Signature
354→    where
355→        H: HashToPoint<Input = u8>,
356→    {
357→        use getrandom::getrandom;
358→
359→        // Generate random salt
360→        let mut salt = [0u8; SALT_LEN];
361→        getrandom(&mut salt).expect("Failed to get random bytes");
362→
363→        Self::sign_with_salt(sk, message, &salt)
364→    }
365→
366→    /// Sign a message with a provided salt.
367→    ///
368→    /// Creates a Falcon-512 signature using a deterministic salt.
369→    /// This is useful for testing or when reproducible signatures are needed.
370→    ///
371→    /// # Arguments
372→    ///
373→    /// * `sk` - The secret key to sign with
374→    /// * `message` - The message bytes to sign
375→    /// * `salt` - A 40-byte salt value
376→    ///
377→    /// # Returns
378→    ///
379→    /// A signature that can be verified with the corresponding verifying key.
380→    ///
381→    /// # Note
382→    ///
383→    /// Using the same salt for different messages may leak information
384→    /// about the secret key. In production, prefer [`sign`](Self::sign).
385→    pub fn sign_with_salt(sk: &SecretKey, message: &[u8], salt: &[u8; SALT_LEN]) -> Signature
386→    where
387→        H: HashToPoint<Input = u8>,
388→    {
389→        let hashed = H::hash_to_point(message, salt);
390→        let hashed_i32: Vec<i32> = hashed.iter().map(|&x| x as i32).collect();
391→
392→        // Initialize seed from salt (seed persists across iterations)
393→        let mut seed = [0u8; SEED_LEN];
394→        seed[..SALT_LEN].copy_from_slice(salt);
395→
396→        // Signing loop - repeat until we find a short enough signature
397→        loop {
398→            let mut rng = ChaCha20::new(&seed);
399→            let mut random_bytes = |n: usize| rng.random_bytes(n);
400→
401→            // Sample preimage
402→            let (s0, s1) = Self::sample_preimage(sk, &hashed_i32, &mut random_bytes);
403→
404→            // Check Euclidean norm
405→            let s0_slice: &[i32] = &s0;
406→            let s1_slice: &[i32] = &s1;
407→            let norm = sqnorm(&[s0_slice, s1_slice]);
408→
409→            if norm <= SIG_BOUND {
410→                // Try to compress s1
411→                let slen = SIG_BYTELEN - HEAD_LEN - SALT_LEN;
412→                if let Some(s1_enc) = compress(&s1, slen) {
413→                    return Signature {
414→                        header: 0x30 + LOGN,
415→                        salt: *salt,
416→                        s1_enc,
417→                    };
418→                }
419→            }
420→
421→            // If norm too large or compression failed, try again with different randomness
422→            // Advance the seed using RNG output
423→            seed[SALT_LEN..].copy_from_slice(&rng.random_bytes(SEED_LEN - SALT_LEN)[..]);
424→        }
425→    }
426→
427→    /// Sign a pre-computed hash point, returning raw (s0, s1) polynomials.
428→    ///
429→    /// This enables signing with custom hash functions (e.g., Poseidon)
430→    /// where the hash-to-point is computed externally.
431→    ///
432→    /// # Arguments
433→    ///
434→    /// * `sk` - The secret key
435→    /// * `hash_point` - Pre-computed hash point (512 coefficients in [0, Q))
436→    /// * `seed` - 56-byte seed for the sampling PRNG
437→    ///
438→    /// # Returns
439→    ///
440→    /// `(s0, s1)` where s0 + s1*h = hash_point (mod q) and ||(s0, s1)|| is small.
441→    /// Coefficients are signed integers (centered around 0).
442→    pub fn sign_prehashed(
443→        sk: &SecretKey,
444→        hash_point: &[i16; N],
445→        seed: &[u8; SEED_LEN],
446→    ) -> (Vec<i32>, Vec<i32>) {
447→        let hashed_i32: Vec<i32> = hash_point.iter().map(|&x| x as i32).collect();
448→        let mut current_seed = *seed;
449→
450→        loop {
451→            let mut rng = ChaCha20::new(&current_seed);
452→            let mut random_bytes = |n: usize| rng.random_bytes(n);
453→
454→            let (s0, s1) = Self::sample_preimage(sk, &hashed_i32, &mut random_bytes);
455→
456→            let s0_slice: &[i32] = &s0;
457→            let s1_slice: &[i32] = &s1;
458→            let norm = sqnorm(&[s0_slice, s1_slice]);
459→
460→            if norm <= SIG_BOUND {
461→                return (s0, s1);
462→            }
463→
464→            // Advance seed
465→            current_seed[SALT_LEN..]
466→                .copy_from_slice(&rng.random_bytes(SEED_LEN - SALT_LEN)[..]);
467→        }
468→    }
469→
470→    /// Sample a short preimage s such that s0 + s1*h = point.
471→    fn sample_preimage<F: FnMut(usize) -> Vec<u8>>(
472→        sk: &SecretKey,
473→        point: &[i32],
474→        random_bytes: &mut F,
475→    ) -> (Vec<i32>, Vec<i32>) {
476→        let [[a, b], [c, d]] = &sk.b0_fft;
477→
478→        // Compute t_fft = (point, 0) * B0^(-1)
479→        // Because the inverse of B0 has a specific form, we can optimize
480→        let point_fft = fft(&point.iter().map(|&x| x as f64).collect::<Vec<_>>());
481→        let q_f64 = Q as f64;
482→
483→        let t0_fft: Vec<Complex> = point_fft
484→            .iter()
485→            .zip(d.iter())
486→            .map(|(&p, &d_i)| {
487→                Complex::new(
488→                    p.re * d_i.re / q_f64 - p.im * d_i.im / q_f64,
489→                    p.re * d_i.im / q_f64 + p.im * d_i.re / q_f64,
490→                )
491→            })
492→            .collect();
493→
494→        let t1_fft: Vec<Complex> = point_fft
495→            .iter()
496→            .zip(b.iter())
497→            .map(|(&p, &b_i)| {
498→                let neg_p = Complex::new(-p.re, -p.im);
499→                Complex::new(
500→                    (neg_p.re * b_i.re - neg_p.im * b_i.im) / q_f64,
501→                    (neg_p.re * b_i.im + neg_p.im * b_i.re) / q_f64,
502→                )
503→            })
504→            .collect();
505→
506→        let t_fft = [t0_fft, t1_fft];
507→
508→        // Sample z using ffsampling
509→        let z_fft = ffsampling_fft(&t_fft, &sk.tree, SIGMIN, random_bytes);
510→
511→        // Compute v = z * B0
512→        let v0_fft = add_fft(&mul_fft(&z_fft[0], a), &mul_fft(&z_fft[1], c));
513→        let v1_fft = add_fft(&mul_fft(&z_fft[0], b), &mul_fft(&z_fft[1], d));
514→
515→        let v0_float = ifft(&v0_fft);
516→        let v1_float = ifft(&v1_fft);
517→
518→        let v0: Vec<i32> = v0_float.iter().map(|&x| x.round() as i32).collect();
519→        let v1: Vec<i32> = v1_float.iter().map(|&x| x.round() as i32).collect();
520→
521→        // s = (point, 0) - v
522→        // s0 = point - v0, s1 = -v1
523→        let s0: Vec<i32> = point.iter().zip(v0.iter()).map(|(&p, &v)| p - v).collect();
524→        let s1: Vec<i32> = v1.iter().map(|&v| -v).collect();
525→
526→        (s0, s1)
527→    }
528→
529→    /// Verify a signature.
530→    ///
531→    /// Checks that a signature is valid for the given message and verifying key.
532→    ///
533→    /// # Arguments
534→    ///
535→    /// * `vk` - The verifying key (public key)
536→    /// * `message` - The message that was supposedly signed
537→    /// * `sig` - The signature to verify
538→    ///
539→    /// # Returns
540→    ///
541→    /// - `Ok(true)` if the signature is valid
542→    /// - `Ok(false)` if the signature is mathematically invalid (wrong key or message)
543→    /// - `Err(FalconError)` if the signature is malformed
544→    pub fn verify(vk: &VerifyingKey, message: &[u8], sig: &Signature) -> Result<bool, FalconError>
545→    where
546→        H: HashToPoint<Input = u8>,
547→    {
548→        // Decompress s1
549→        let s1 = decompress(&sig.s1_enc, N).ok_or(FalconError::DecompressionFailed)?;
550→
551→        // Hash the message
552→        let hashed = H::hash_to_point(message, &sig.salt);
553→        let hashed_i32: Vec<i32> = hashed.iter().map(|&x| x as i32).collect();
554→
555→        // Compute s0 = hashed - s1 * h
556→        let h_vec: Vec<i32> = vk.h.iter().copied().collect();
557→        let s1_h = mul_zq(&s1, &h_vec);
558→        let s0 = sub_zq(&hashed_i32, &s1_h);
559→
560→        // Normalize s0 coefficients to (-q/2, q/2]
561→        let s0_centered: Vec<i32> = s0
562→            .iter()
563→            .map(|&c| {
564→                let c = c.rem_euclid(Q);
565→                if c > Q / 2 {
566→                    c - Q
567→                } else {
568→                    c
569→                }
570→            })
571→            .collect();
572→
573→        // Check signature norm
574→        let s0_slice: &[i32] = &s0_centered;
575→        let s1_slice: &[i32] = &s1;
576→        let norm = sqnorm(&[s0_slice, s1_slice]);
577→
578→        if norm > SIG_BOUND {
579→            return Ok(false);
580→        }
581→
582→        Ok(true)
583→    }
584→}
