 1→//! Hint generation for Falcon verification.
 2→//!
 3→//! Generates the mul_hint = INTT(NTT(s1) * pk_h_ntt) that allows
 4→//! Cairo to verify NTT products without computing INTT on-chain.
 5→
 6→use crate::ntt::{ntt, intt, mul_ntt};
 7→use crate::Q;
 8→
 9→/// Generate INTT(NTT(s1) * pk_h_ntt) — the mul_hint for verification.
10→pub fn generate_mul_hint(s1: &[u16], pk_h_ntt: &[u16]) -> Vec<u16> {
11→    let s1_i32: Vec<i32> = s1.iter().map(|&v| v as i32).collect();
12→    let pk_i32: Vec<i32> = pk_h_ntt.iter().map(|&v| v as i32).collect();
13→
14→    let s1_ntt = ntt(&s1_i32);
15→    let product_ntt = mul_ntt(&s1_ntt, &pk_i32);
16→    let product = intt(&product_ntt);
17→
18→    product
19→        .iter()
20→        .map(|&v| v.rem_euclid(Q) as u16)
21→        .collect()
22→}
23→
24→#[cfg(test)]
25→mod tests {
26→    use super::*;
27→
28→    #[test]
29→    fn test_hint_generation() {
30→        // s1 = [1, 0, 0, ...], pk_ntt = NTT([1, 0, 0, ...])
31→        let mut s1 = vec![0u16; 512];
32→        s1[0] = 1;
33→        let pk_coeff: Vec<i32> = s1.iter().map(|&v| v as i32).collect();
34→        let pk_ntt = ntt(&pk_coeff);
35→        let pk_u16: Vec<u16> = pk_ntt.iter().map(|&v| v.rem_euclid(Q) as u16).collect();
36→
37→        let hint = generate_mul_hint(&s1, &pk_u16);
38→        assert_eq!(hint.len(), 512);
39→        // hint = INTT(NTT([1,0...]) * NTT([1,0...])) = [1,0...]
40→        assert_eq!(hint[0], 1);
41→        for i in 1..512 {
42→            assert_eq!(hint[i], 0, "expected 0 at index {i}, got {}", hint[i]);
43→        }
44→    }
45→}
