  1→//! Hash-to-point trait for customizable hash functions.
  2→//!
  3→//! Falcon requires hashing messages to points in Z_q[X]/(X^n + 1).
  4→//! This module provides the trait and a default SHAKE256 implementation.
  5→
  6→use crate::{N, Q};
  7→
  8→/// Trait for hashing message to polynomial in Z_q[x]/(x^n + 1).
  9→///
 10→/// This trait allows swapping the hash function used in Falcon,
 11→/// enabling use of Poseidon for Starknet compatibility.
 12→///
 13→/// The associated type `Input` determines the element type for message and salt:
 14→/// - `u8` for byte-oriented hashing (SHAKE256)
 15→/// - `Felt` for field-element hashing (Poseidon/Starknet)
 16→pub trait HashToPoint {
 17→    /// Element type for message and salt slices.
 18→    type Input;
 19→
 20→    /// Hash a message with salt to a polynomial in Z_q[x].
 21→    fn hash_to_point(message: &[Self::Input], salt: &[Self::Input]) -> [i16; N];
 22→}
 23→
 24→/// SHAKE256-based hash (matches Python reference implementation).
 25→#[cfg(feature = "shake")]
 26→pub struct Shake256Hash;
 27→
 28→#[cfg(feature = "shake")]
 29→impl HashToPoint for Shake256Hash {
 30→    type Input = u8;
 31→
 32→    fn hash_to_point(message: &[u8], salt: &[u8]) -> [i16; N] {
 33→        use sha3::{
 34→            digest::{ExtendableOutput, Update, XofReader},
 35→            Shake256,
 36→        };
 37→
 38→        let mut hasher = Shake256::default();
 39→        hasher.update(salt);
 40→        hasher.update(message);
 41→        let mut reader = hasher.finalize_xof();
 42→
 43→        // Rejection sampling parameter: k = floor(2^16 / q)
 44→        let k = (1u32 << 16) / (Q as u32);
 45→        let mut hashed = [0i16; N];
 46→        let mut i = 0;
 47→
 48→        while i < N {
 49→            let mut buf = [0u8; 2];
 50→            reader.read(&mut buf);
 51→            // Big-endian as per Python reference
 52→            let elt = ((buf[0] as u32) << 8) | (buf[1] as u32);
 53→
 54→            // Rejection sampling to ensure uniform distribution
 55→            if elt < k * (Q as u32) {
 56→                hashed[i] = (elt % (Q as u32)) as i16;
 57→                i += 1;
 58→            }
 59→        }
 60→
 61→        hashed
 62→    }
 63→}
 64→
