  1→//! Number Theoretic Transform over Z_q[x]/(x^n + 1).
  2→
  3→use crate::constants::{ntt_roots, I2, INV_MOD_Q, SQR1};
  4→use crate::Q;
  5→
  6→/// Split a polynomial in NTT representation.
  7→pub fn split_ntt(f_ntt: &[i32]) -> (Vec<i32>, Vec<i32>) {
  8→    let n = f_ntt.len();
  9→    let w = ntt_roots(n);
 10→    let mut f0_ntt = vec![0i32; n / 2];
 11→    let mut f1_ntt = vec![0i32; n / 2];
 12→
 13→    for i in 0..n / 2 {
 14→        let sum = (f_ntt[2 * i] + f_ntt[2 * i + 1]).rem_euclid(Q);
 15→        let diff = (f_ntt[2 * i] - f_ntt[2 * i + 1]).rem_euclid(Q);
 16→        f0_ntt[i] = ((I2 as i64 * sum as i64) % Q as i64) as i32;
 17→        f1_ntt[i] =
 18→            ((I2 as i64 * diff as i64 * INV_MOD_Q[w[2 * i] as usize] as i64) % Q as i64) as i32;
 19→    }
 20→    (f0_ntt, f1_ntt)
 21→}
 22→
 23→/// Merge two polynomials in NTT representation.
 24→pub fn merge_ntt(f0_ntt: &[i32], f1_ntt: &[i32]) -> Vec<i32> {
 25→    let n = 2 * f0_ntt.len();
 26→    let w = ntt_roots(n);
 27→    let mut f_ntt = vec![0i32; n];
 28→
 29→    for i in 0..n / 2 {
 30→        let wf1 = ((w[2 * i] as i64 * f1_ntt[i] as i64) % Q as i64) as i32;
 31→        f_ntt[2 * i] = (f0_ntt[i] + wf1).rem_euclid(Q);
 32→        f_ntt[2 * i + 1] = (f0_ntt[i] - wf1).rem_euclid(Q);
 33→    }
 34→    f_ntt
 35→}
 36→
 37→/// Compute NTT of a polynomial (coefficient -> NTT representation).
 38→pub fn ntt(f: &[i32]) -> Vec<i32> {
 39→    let n = f.len();
 40→    if n > 2 {
 41→        let mut f0 = vec![0i32; n / 2];
 42→        let mut f1 = vec![0i32; n / 2];
 43→        for i in 0..n / 2 {
 44→            f0[i] = f[2 * i];
 45→            f1[i] = f[2 * i + 1];
 46→        }
 47→        let f0_ntt = ntt(&f0);
 48→        let f1_ntt = ntt(&f1);
 49→        merge_ntt(&f0_ntt, &f1_ntt)
 50→    } else {
 51→        let mut f_ntt = vec![0i32; n];
 52→        f_ntt[0] = (f[0] + ((SQR1 as i64 * f[1] as i64) % Q as i64) as i32).rem_euclid(Q);
 53→        f_ntt[1] = (f[0] - ((SQR1 as i64 * f[1] as i64) % Q as i64) as i32).rem_euclid(Q);
 54→        f_ntt
 55→    }
 56→}
 57→
 58→/// Compute inverse NTT (NTT -> coefficient representation).
 59→pub fn intt(f_ntt: &[i32]) -> Vec<i32> {
 60→    let n = f_ntt.len();
 61→    if n > 2 {
 62→        let (f0_ntt, f1_ntt) = split_ntt(f_ntt);
 63→        let f0 = intt(&f0_ntt);
 64→        let f1 = intt(&f1_ntt);
 65→        // merge
 66→        let mut f = vec![0i32; n];
 67→        for i in 0..n / 2 {
 68→            f[2 * i] = f0[i];
 69→            f[2 * i + 1] = f1[i];
 70→        }
 71→        f
 72→    } else {
 73→        let mut f = vec![0i32; n];
 74→        let sum = (f_ntt[0] + f_ntt[1]).rem_euclid(Q);
 75→        let diff = (f_ntt[0] - f_ntt[1]).rem_euclid(Q);
 76→        f[0] = ((I2 as i64 * sum as i64) % Q as i64) as i32;
 77→        f[1] = ((I2 as i64 * INV_MOD_Q[SQR1 as usize] as i64 * diff as i64) % Q as i64) as i32;
 78→        f
 79→    }
 80→}
 81→
 82→/// Addition of two polynomials in Z_q.
 83→pub fn add_zq(f: &[i32], g: &[i32]) -> Vec<i32> {
 84→    assert_eq!(f.len(), g.len());
 85→    f.iter()
 86→        .zip(g.iter())
 87→        .map(|(&a, &b)| (a + b).rem_euclid(Q))
 88→        .collect()
 89→}
 90→
 91→/// Negation of a polynomial in Z_q.
 92→pub fn neg_zq(f: &[i32]) -> Vec<i32> {
 93→    f.iter().map(|&a| (-a).rem_euclid(Q)).collect()
 94→}
 95→
 96→/// Subtraction of two polynomials in Z_q.
 97→pub fn sub_zq(f: &[i32], g: &[i32]) -> Vec<i32> {
 98→    add_zq(f, &neg_zq(g))
 99→}
100→
101→/// Multiplication in NTT representation (pointwise).
102→pub fn mul_ntt(f_ntt: &[i32], g_ntt: &[i32]) -> Vec<i32> {
103→    assert_eq!(f_ntt.len(), g_ntt.len());
104→    f_ntt
105→        .iter()
106→        .zip(g_ntt.iter())
107→        .map(|(&a, &b)| ((a as i64 * b as i64) % Q as i64) as i32)
108→        .collect()
109→}
110→
111→/// Division in NTT representation (pointwise).
112→pub fn div_ntt(f_ntt: &[i32], g_ntt: &[i32]) -> Option<Vec<i32>> {
113→    assert_eq!(f_ntt.len(), g_ntt.len());
114→    if g_ntt.iter().any(|&x| x == 0) {
115→        return None;
116→    }
117→    Some(
118→        f_ntt
119→            .iter()
120→            .zip(g_ntt.iter())
121→            .map(|(&a, &b)| ((a as i64 * INV_MOD_Q[b as usize] as i64) % Q as i64) as i32)
122→            .collect(),
123→    )
124→}
125→
126→/// Multiplication of two polynomials in coefficient representation.
127→pub fn mul_zq(f: &[i32], g: &[i32]) -> Vec<i32> {
128→    intt(&mul_ntt(&ntt(f), &ntt(g)))
129→}
130→
131→/// Division of two polynomials in coefficient representation.
132→pub fn div_zq(f: &[i32], g: &[i32]) -> Option<Vec<i32>> {
133→    div_ntt(&ntt(f), &ntt(g)).map(|r| intt(&r))
134→}
135→
