 1→//! Serialization utilities for generating snforge-compatible JSON test data.
 2→//!
 3→//! Produces JSON in the format expected by Cairo's `read_json` + `Serde::deserialize`.
 4→//! Values must be JSON integers (not strings) for snforge to parse correctly.
 5→
 6→use crate::poseidon_hash::Felt;
 7→use num_bigint::BigUint;
 8→use serde_json::{json, Number, Value};
 9→
10→/// Serialize an array of u16 values as Cairo Serde: [length, v0, v1, ...]
11→fn serde_u16_array(values: &[u16]) -> Vec<Value> {
12→    let mut out = Vec::with_capacity(values.len() + 1);
13→    out.push(Value::Number(Number::from(values.len())));
14→    for &v in values {
15→        out.push(Value::Number(Number::from(v)));
16→    }
17→    out
18→}
19→
20→/// Serialize an array of Felt values as Cairo Serde: [length, f0, f1, ...]
21→/// Felt values that fit in u64 are serialized as JSON numbers.
22→/// Larger values are serialized as decimal strings (snforge handles both).
23→fn serde_felt_array(values: &[Felt]) -> Vec<Value> {
24→    let mut out = Vec::with_capacity(values.len() + 1);
25→    out.push(Value::Number(Number::from(values.len())));
26→    for v in values {
27→        out.push(felt_to_json_value(v));
28→    }
29→    out
30→}
31→
32→fn felt_to_json_value(f: &Felt) -> Value {
33→    let bytes = f.to_bytes_be();
34→    let num = BigUint::from_bytes_be(&bytes);
35→    let decimal = num.to_string();
36→    // Use arbitrary_precision to emit large numbers as JSON integers (not strings)
37→    Value::Number(Number::from_string_unchecked(decimal))
38→}
39→
40→/// Generate snforge-compatible JSON for hash_to_point test data.
41→pub fn hash_to_point_test_json(
42→    message: &[Felt],
43→    salt: &[Felt],
44→    expected: &[u16],
45→) -> Value {
46→    let mut payload = Vec::new();
47→    payload.extend(serde_felt_array(message));
48→    payload.extend(serde_felt_array(salt));
