  }, [keypair, setStep])

  const hasKeypair = Option.isSome(keypair)
  const isLoading = step.step !== "idle" && step.step !== "complete" && step.step !== "error"

  return (
    <section id="verify" className="px-6 py-20 lg:px-8">
